-- M.Ed I Year students

-- ═══════════════════════════════════════════════════════════════════
-- 5. STUDENT SESSIONS
-- ═══════════════════════════════════════════════════════════════════
  SELECT 1, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c ON c.class = 'B.Ed I Year'
  JOIN class_sections cs ON cs.class_id = c.id
  WHERE s.note = 'IMP_BED1'
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id = 1 AND ss2.student_id = s.id);

  SELECT 1, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c ON c.class = 'B.Ed II Year'
  JOIN class_sections cs ON cs.class_id = c.id
  WHERE s.note = 'IMP_BED2'
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id = 1 AND ss2.student_id = s.id);

  SELECT 1, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c ON c.class = 'M.Ed I Year'
  JOIN class_sections cs ON cs.class_id = c.id
  WHERE s.note = 'IMP_MED1'
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id = 1 AND ss2.student_id = s.id);

  SELECT 1, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c ON c.class = 'M.Ed II Year'
  JOIN class_sections cs ON cs.class_id = c.id
  WHERE s.note = 'IMP_MED2'
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id = 1 AND ss2.student_id = s.id);

-- Note: IMP_xxx batch markers are kept permanently for idempotency

SET FOREIGN_KEY_CHECKS = 1;